public <Old, New> MessageMapping register(
      String oldTypeName,
      Class<Old> oldClass,
      Function<Old, New> transform
    ) {
      transformations.add(new MessageTransformation(
        oldTypeName,
        json -> {
          try {
            Old old = objectMapper.readValue(json, oldClass);
            return Optional.of(transform.apply(old));
          } catch (IOException e) {
            return Optional.empty();
          }
        }
      ));
      return this;
    }

    public <New> MessageMapping register(
      String oldTypeName,
      Function<JsonNode, New> transform
    ) {
      transformations.add(new MessageTransformation(
        oldTypeName,
        json -> {
          try {
            JsonNode node = objectMapper.readTree(json);
            return Optional.of(transform.apply(node));
          } catch (IOException e) {
            return Optional.empty();
          }
        }
      ));
      return this;
    }

